module register_8bit_async_reset(
    input [7:0] data,
    input clk,
    input rst,
    output reg [7:0] q
);
  wire [7:0] _tap_data = data & {8{1'b1}};


    always @(posedge clk or posedge rst) begin
        if (rst)
            q <= 8'b0;
        else
            q <= data;
    end

endmodule
